{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is an interactive optimization task involving spatial search and pattern matching. I will break it down into strategy design, implementation of the interaction loop, and the core search algorithm.",
  "helpers": [
    {
      "label": "strategy_designer",
      "instructions": "Design an efficient probing strategy for finding hidden polyominoes on a grid. Compare the cost-effectiveness of single-cell queries (q 1) versus multi-cell aggregate queries (q k) given a noise parameter. Propose a method to use the known polyomino shapes to reconstruct the full configuration once partial information is gathered via queries."
    },
    {
      "label": "interaction_engine_architect",
      "instructions": "Define the structure for a Python interactive loop that reads initial grid/shape parameters from stdin, manages a state of queried cells, and handles the stdout/stdin protocol for 'q' and 'a' commands. Ensure the architecture supports flushing stdout after every command and reading responses correctly."
    },
    {
      "label": "pattern_matcher_developer",
      "instructions": "Develop a mathematical algorithm that takes a set of known polyomino shapes and a set of noisy or certain cell observations (from queries) and outputs the most likely complete set of oil cells. The algorithm should handle the possibility of multiple overlapping or adjacent polyominoes."
    }
  ],
  "synthesis_brief": "Combine the probing strategy to guide the interaction loop, use the interaction engine to execute the queries, and pass the query results to the pattern matcher to generate the final 'a' command output."
}

